module accu (
    input               clk,
    input               rst_n,
    input       [7:0]   data_in,
    input               valid_in,
    output  reg         valid_out,
    output  reg [9:0]   data_out
);

reg [1:0] cnt;
reg [9:0] sum;
reg valid_out_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin

        cnt <= 0;
        sum <= 0;
        valid_out_reg <= 0;
    end else begin

        if (valid_in == 1) begin

            cnt <= cnt + 1;

            sum <= sum + data_in;

            if (cnt == 4) begin

                valid_out_reg <= 1;

                cnt <= 0;
                sum <= 0;
            end
        end else begin

            valid_out_reg <= 0;
        end
    end
end

assign valid_out = valid_out_reg;
assign data_out = sum;
endmodule
